/* Example for a variable font with 'wght' (weight) and 'wdth' (width) axes */
h1 {
  font-family: "Inter Variable", sans-serif;
  font-variation-settings: "wght" 700, "wdth" 100; /* Default */
}

@media (max-width: 768px) {
  h1 {
    font-variation-settings: "wght" 600, "wdth" 90; /* Slightly lighter and narrower on smaller screens */
    /* Or even an 'opsz' (optical size) axis if available */
    /* font-variation-settings: "wght" 600, "wdth" 90, "opsz" 18; */
  }
}

/* For a custom axis, e.g., 'GRAD' for grade */
.product-title {
  font-family: "MyProductSans Variable", sans-serif;
  font-variation-settings: "wght" 500, "GRAD" 100;
}
